4	pub fn load_claude_sessions(paths: &clui_config::Paths) -> Vec<SessionEntry> {
5	    let projects_dir = &paths.claude_projects_dir;
6	    let Ok(proj_entries) = std::fs::read_dir(projects_dir) else {
7	        return Vec::new();
8	    };
9	
10	    let mut sessions = Vec::new();
11	    for proj in proj_entries.filter_map(|e| e.ok()) {
12	        let Ok(proj_files) = std::fs::read_dir(proj.path()) else {
13	            continue;
14	        };
15	        for jsonl_file in proj_files
16	            .filter_map(|e| e.ok())
17	            .filter(|e| e.path().extension().and_then(|s| s.to_str()) == Some("jsonl"))
18	        {
19	            let Ok(file) = std::fs::File::open(jsonl_file.path()) else {
20	                continue;
21	            };
22	            let reader = std::io::BufReader::new(file);
23	            let mut first_user_msg: Option<String> = None;
24	            for line in reader.lines().filter_map(|l| l.ok()) {
25	                if let Ok(val) = serde_json::from_str::<serde_json::Value>(&line) {
26	                    if val["type"] == "user" {
27	                        let text = val["message"]["content"]
28	                            .as_str()
29	                            .map(|s| s.to_string())
30	                            .or_else(|| {
31	                                val["message"]["content"][0]["text"]
32	                                    .as_str()
33	                                    .map(|s| s.to_string())
34	                            });
35	                        if let Some(t) = text {
36	                            first_user_msg = Some(t);
37	                            break;
38	                        }
39	                    }
40	                }
41	            }
42	            if let Some(title) = first_user_msg {
43	                let path_str = jsonl_file.path().to_string_lossy().to_string();
44	                let modified = jsonl_file
45	                    .metadata()
46	                    .ok()
47	                    .and_then(|m| m.modified().ok())
48	                    .map(|t| {
49	                        let secs = t.duration_since(std::time::UNIX_EPOCH)
50	                            .unwrap_or_default().as_secs();
51	                        format!("{}", secs)
52	                    })
53	                    .unwrap_or_default();
54	                sessions.push(SessionEntry { title, path: path_str, modified });
55	            }
56	        }
57	    }
58	    sessions.sort_by(|a, b| b.modified.cmp(&a.modified));
59	    sessions
60	}
